import React, { useEffect, useState } from 'react';
import Layout from '../components/layout/Layout';
import api from '../services/api';

export default function Settings() {
  const [form, setForm] = useState({
    shopName: '', shopAddress: '', shopCity: '', shopState: '', shopPincode: '',
    shopPhone: '', shopEmail: '', shopGstin: '', shopStateCode: '',
    bankName: '', bankAccount: '', bankIfsc: '', bankBranch: '',
    invoicePrefix: 'INV', termsAndConditions: '', gstType: 'intra', lowStockThreshold: 5,
  });
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    api.get('/settings').then((r) => {
      const d = r.data.data;
      setForm((f) => ({ ...f, ...d }));
    }).finally(() => setLoading(false));
  }, []);

  const setField = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const handleSave = async () => {
    setSaving(true); setSuccess(''); setError('');
    try {
      await api.put('/settings', form);
      setSuccess('Settings saved successfully');
    } catch (err) {
      setError('Failed to save settings');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <Layout title="Settings"><div className="loading"><div className="spinner" /></div></Layout>;

  return (
    <Layout title="Settings">
      {success && <div className="alert alert-success">{success}</div>}
      {error && <div className="alert alert-danger">{error}</div>}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        {/* Shop Info */}
        <div className="card">
          <div className="card-header"><span className="card-title">Shop Information</span></div>
          <div className="card-body">
            <div className="form-group">
              <label className="form-label">Shop Name *</label>
              <input className="form-control" value={form.shopName} onChange={(e) => setField('shopName', e.target.value)} />
            </div>
            <div className="form-group">
              <label className="form-label">Address</label>
              <input className="form-control" value={form.shopAddress} onChange={(e) => setField('shopAddress', e.target.value)} />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">City</label>
                <input className="form-control" value={form.shopCity} onChange={(e) => setField('shopCity', e.target.value)} />
              </div>
              <div className="form-group">
                <label className="form-label">State</label>
                <input className="form-control" value={form.shopState} onChange={(e) => setField('shopState', e.target.value)} />
              </div>
              <div className="form-group">
                <label className="form-label">Pincode</label>
                <input className="form-control" value={form.shopPincode} onChange={(e) => setField('shopPincode', e.target.value)} />
              </div>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Phone</label>
                <input className="form-control" value={form.shopPhone} onChange={(e) => setField('shopPhone', e.target.value)} />
              </div>
              <div className="form-group">
                <label className="form-label">Email</label>
                <input className="form-control" type="email" value={form.shopEmail} onChange={(e) => setField('shopEmail', e.target.value)} />
              </div>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">GSTIN</label>
                <input className="form-control" value={form.shopGstin} onChange={(e) => setField('shopGstin', e.target.value.toUpperCase())} />
              </div>
              <div className="form-group">
                <label className="form-label">State Code</label>
                <input className="form-control" value={form.shopStateCode} onChange={(e) => setField('shopStateCode', e.target.value)} maxLength={2} />
              </div>
            </div>
          </div>
        </div>

        {/* Invoice & GST */}
        <div className="card">
          <div className="card-header"><span className="card-title">Invoice & GST Settings</span></div>
          <div className="card-body">
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Invoice Prefix</label>
                <input className="form-control" value={form.invoicePrefix} onChange={(e) => setField('invoicePrefix', e.target.value)} placeholder="INV" />
              </div>
              <div className="form-group">
                <label className="form-label">Default GST Type</label>
                <select className="form-control" value={form.gstType} onChange={(e) => setField('gstType', e.target.value)}>
                  <option value="intra">Intra-State (CGST + SGST)</option>
                  <option value="inter">Inter-State (IGST)</option>
                </select>
              </div>
            </div>
            <div className="form-group">
              <label className="form-label">Low Stock Alert Threshold (Default)</label>
              <input className="form-control" type="number" min={0} value={form.lowStockThreshold} onChange={(e) => setField('lowStockThreshold', Number(e.target.value))} />
            </div>
            <div className="form-group">
              <label className="form-label">Terms & Conditions (printed on invoice)</label>
              <textarea className="form-control" rows={4} value={form.termsAndConditions} onChange={(e) => setField('termsAndConditions', e.target.value)} />
            </div>
          </div>
        </div>

        {/* Bank Details */}
        <div className="card">
          <div className="card-header"><span className="card-title">Bank Details</span></div>
          <div className="card-body">
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Bank Name</label>
                <input className="form-control" value={form.bankName} onChange={(e) => setField('bankName', e.target.value)} />
              </div>
              <div className="form-group">
                <label className="form-label">Account Number</label>
                <input className="form-control" value={form.bankAccount} onChange={(e) => setField('bankAccount', e.target.value)} />
              </div>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">IFSC Code</label>
                <input className="form-control" value={form.bankIfsc} onChange={(e) => setField('bankIfsc', e.target.value.toUpperCase())} />
              </div>
              <div className="form-group">
                <label className="form-label">Branch</label>
                <input className="form-control" value={form.bankBranch} onChange={(e) => setField('bankBranch', e.target.value)} />
              </div>
            </div>
          </div>
        </div>
      </div>

      <div style={{ marginTop: 20, display: 'flex', justifyContent: 'flex-end' }}>
        <button className="btn btn-primary btn-lg" onClick={handleSave} disabled={saving}>
          {saving ? 'Saving...' : 'Save Settings'}
        </button>
      </div>
    </Layout>
  );
}
